document.addEventListener("scroll",function(){var scrollPosition=window.scrollY;var button=document.getElementById('scrollToTopBtn');if(scrollPosition>250){button.style.display='block'}else{button.style.display='none'}});document.getElementById('scrollToTopBtn').addEventListener('click',function(){anime({targets:document.documentElement,scrollTop:0,duration:200,})});document.addEventListener("readystatechange",function(event){if(event.target.readyState=="interactive"){fetch('./files/uqunscramble.c').then(response=>response.text()).then(text=>{document.querySelector('.c_code').textContent=text;hljs.highlightElement(document.querySelector('.c_code'))})
fetch('./files/rcvt.py').then(response=>response.text()).then(text=>{document.querySelector('.python_code0').textContent=text;hljs.highlightElement(document.querySelector('.python_code0'))})
fetch('./files/binaryTrainer.py').then(response=>response.text()).then(text=>{document.querySelector('.python_code1').textContent=text;hljs.highlightElement(document.querySelector('.python_code1'))})}})
